// // This is a 1-to-4 demultiplexer that outputs one of four 1-bit input signals based on a 2-bit selection input.
module top_module(
    input wire [3:0] in,
    input wire [1:0] sel,
    output reg out
);always @(*) begin
    case (sel)
        2'b00: out = in[0];
        2'b01: out = in[1];
        2'b10: out = in[2];
        2'b11: out = in[3];
    endcase
end

endmodule
